<?php
declare(strict_types=1);namespace App\Services\ControlEscaneres\Import;final class LocalFixtureManager{public function assertLocal(string$env,string$host,string$db,string$expected,bool$confirmed,bool$interactive):void{if(!in_array($env,['local','development','testing'],true)||!in_array($host,['localhost','127.0.0.1','::1'],true)||$db!==$expected||!in_array($db,['ferrocheck','ferrocheck_test'],true)||!$confirmed||!$interactive)throw new \DomainException('Carga local bloqueada.');}public function load(\PDO$pdo,string$file):array{$validation=(new InitialScannerCsvValidator())->validate($file);if($validation['invalid']>0)throw new \DomainException('El archivo contiene filas inválidas.');$h=fopen($file,'rb');$headers=fgetcsv($h);$rows=[];while(($values=fgetcsv($h))!==false){$r=array_combine($headers,array_pad($values,count($headers),''));if(!preg_match('/^SC-9[0-9]{3,}$/',$r['codigo']))throw new \DomainException('Código fuera del rango reservado para fixtures.');$rows[]=$r;}fclose($h);$pdo->beginTransaction();try{$check=$pdo->prepare('SELECT COUNT(*) FROM scanners WHERE codigo=:codigo OR (:serie<>\'\' AND numero_serie=:serie) OR (:imei<>\'\' AND imei=:imei)');$insert=$pdo->prepare('INSERT INTO scanners(codigo,codigo_qr,marca,modelo,numero_serie,imei,telefono,iccid,estado,activo)VALUES(:codigo,:qr,:marca,:modelo,:serie,:imei,:telefono,:iccid,:estado,:activo)');foreach($rows as$r){$check->execute(['codigo'=>$r['codigo'],'serie'=>$r['serie'],'imei'=>$r['imei']]);if((int)$check->fetchColumn()>0)throw new \DomainException('Fixture duplicado en base.');$insert->execute(['codigo'=>$r['codigo'],'qr'=>'FIXTURE:'.$r['codigo'],'marca'=>$r['marca'],'modelo'=>$r['modelo'],'serie'=>$r['serie']?:null,'imei'=>$r['imei']?:null,'telefono'=>$r['telefono']?:null,'iccid'=>$r['iccid']?:null,'estado'=>$r['estado'],'activo'=>(int)$r['activo']]);}$pdo->commit();return['inserted'=>count($rows)];}catch(\Throwable$e){if($pdo->inTransaction())$pdo->rollBack();throw$e;}}public function cleanupPreview(\PDO$pdo):array{$s=$pdo->query("SELECT s.codigo,(SELECT COUNT(*) FROM scanner_movimientos m WHERE m.scanner_id=s.id) movements FROM scanners s WHERE s.codigo LIKE 'SC-9%'");return$s->fetchAll(\PDO::FETCH_ASSOC);}}
